import{_ as r,o as a,c as t,ag as l}from"./chunks/framework.DgcAjFZS.js";const d=JSON.parse('{"title":"学习路线图","description":"","frontmatter":{},"headers":[],"relativePath":"inference/roadmap.md","filePath":"inference/roadmap.md"}'),i={name:"inference/roadmap.md"};function n(o,e,s,g,h,p){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="学习路线图" tabindex="-1">学习路线图 <a class="header-anchor" href="#学习路线图" aria-label="Permalink to &quot;学习路线图&quot;">​</a></h1><blockquote><p>Pan老师的 Agentic RL + 大模型推理优化 学习计划 创建时间：2026-03-02</p></blockquote><h2 id="总体规划" tabindex="-1">总体规划 <a class="header-anchor" href="#总体规划" aria-label="Permalink to &quot;总体规划&quot;">​</a></h2><p>两条线并行，每条线分3个阶段，预计3-4个月完成核心内容。 建议每周两条线交替推进，保持新鲜感。</p><hr><h2 id="线路一-agentic-rl" tabindex="-1">线路一：Agentic RL <a class="header-anchor" href="#线路一-agentic-rl" aria-label="Permalink to &quot;线路一：Agentic RL&quot;">​</a></h2><h3 id="阶段1-从dpo到online-rl-第1-3周" tabindex="-1">阶段1：从DPO到Online RL（第1-3周） <a class="header-anchor" href="#阶段1-从dpo到online-rl-第1-3周" aria-label="Permalink to &quot;阶段1：从DPO到Online RL（第1-3周）&quot;">​</a></h3><p>你已经有SFT+DPO经验，这个阶段补上在线RL训练LLM的gap。</p><p><strong>核心概念：</strong></p><ul><li>PPO in LLM context（和你之前DRL的PPO区别在哪）</li><li>GRPO（Group Relative Policy Optimization）— DeepSeek的核心方法</li><li>RLOO（REINFORCE Leave-One-Out）</li><li>Online vs Offline RL for LLM alignment</li></ul><p><strong>必读论文：</strong></p><ul><li>[ ] <a href="https://arxiv.org/abs/2203.02155" target="_blank" rel="noreferrer">InstructGPT (Ouyang et al., 2022)</a> — RLHF经典，快速过一遍</li><li>[ ] <a href="https://arxiv.org/abs/2305.18290" target="_blank" rel="noreferrer">DPO (Rafailov et al., 2023)</a> — 你做过，重新从理论角度审视</li><li>[ ] <a href="https://arxiv.org/abs/2501.12948" target="_blank" rel="noreferrer">DeepSeek-R1 (2025)</a> — 重点！GRPO + RL for reasoning</li><li>[ ] <a href="https://arxiv.org/abs/2402.03300" target="_blank" rel="noreferrer">GRPO原始论文 - DeepSeekMath (2024)</a> — GRPO方法细节</li><li>[ ] <a href="https://arxiv.org/abs/2405.07863" target="_blank" rel="noreferrer">Online DPO / RLHF对比研究</a> — 理解online vs offline的trade-off</li></ul><p><strong>实操：</strong></p><ul><li>[ ] 用 <a href="https://github.com/huggingface/trl" target="_blank" rel="noreferrer">TRL库</a> 跑通一个GRPO训练（小模型即可，如Qwen2.5-1.5B）</li><li>[ ] 对比PPO vs DPO vs GRPO在同一任务上的效果</li></ul><h3 id="阶段2-agent框架与reward设计-第4-6周" tabindex="-1">阶段2：Agent框架与Reward设计（第4-6周） <a class="header-anchor" href="#阶段2-agent框架与reward设计-第4-6周" aria-label="Permalink to &quot;阶段2：Agent框架与Reward设计（第4-6周）&quot;">​</a></h3><p>这是agentic RL的核心 — 怎么让模型学会用工具、多步推理。</p><p><strong>核心概念：</strong></p><ul><li>ReAct范式（Reasoning + Acting）</li><li>Tool use / Function calling 的RL训练</li><li>Process Reward Model (PRM) vs Outcome Reward Model (ORM)</li><li>Multi-turn interaction的reward设计</li><li>Verifiable rewards vs learned rewards</li></ul><p><strong>必读论文：</strong></p><ul><li>[ ] <a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">ReAct (Yao et al., 2023)</a> — agent推理范式</li><li>[ ] <a href="https://arxiv.org/abs/2302.04761" target="_blank" rel="noreferrer">Toolformer (Schick et al., 2023)</a> — 自学工具使用</li><li>[ ] <a href="https://arxiv.org/abs/2305.20050" target="_blank" rel="noreferrer">Let&#39;s Verify Step by Step (Lightman et al., 2023)</a> — PRM</li><li>[ ] <a href="https://openai.com/research/improving-mathematical-reasoning-with-process-reward-models" target="_blank" rel="noreferrer">OpenAI Process Reward Model</a></li><li>[ ] <a href="https://arxiv.org/abs/2504.20073" target="_blank" rel="noreferrer">RAGEN (2025)</a> — Agentic RL训练框架</li><li>[ ] <a href="https://arxiv.org/abs/2503.09516" target="_blank" rel="noreferrer">Search-R1 (2025)</a> — RL训练agent做搜索</li></ul><p><strong>实操：</strong></p><ul><li>[ ] 实现一个简单的tool-use环境（如calculator + search）</li><li>[ ] 用GRPO训练模型在该环境中学会调用工具</li><li>[ ] 实现PRM并对比ORM效果</li></ul><h3 id="阶段3-前沿与深入-第7-10周" tabindex="-1">阶段3：前沿与深入（第7-10周） <a class="header-anchor" href="#阶段3-前沿与深入-第7-10周" aria-label="Permalink to &quot;阶段3：前沿与深入（第7-10周）&quot;">​</a></h3><p><strong>进阶主题：</strong></p><ul><li>[ ] Multi-agent RL — 多个LLM agent协作</li><li>[ ] Self-play / Constitutional AI</li><li>[ ] RL scaling laws for LLM</li><li>[ ] Test-time compute scaling（inference-time RL）</li></ul><p><strong>前沿论文（持续更新）：</strong></p><ul><li>[ ] <a href="https://arxiv.org/abs/2408.03314" target="_blank" rel="noreferrer">Scaling LLM Test-Time Compute (Snell et al., 2024)</a></li><li>[ ] <a href="https://arxiv.org/abs/2203.14465" target="_blank" rel="noreferrer">STaR / Quiet-STaR</a> — 自我改进推理</li><li>[ ] [STILL-ALIVE系列] — RL for long-horizon agent tasks</li></ul><p><strong>项目：</strong></p><ul><li>[ ] 端到端实现一个agentic RL训练pipeline</li><li>[ ] 写一篇技术博客总结agentic RL的核心方法论</li></ul><hr><h2 id="线路二-大模型推理优化" tabindex="-1">线路二：大模型推理优化 <a class="header-anchor" href="#线路二-大模型推理优化" aria-label="Permalink to &quot;线路二：大模型推理优化&quot;">​</a></h2><h3 id="阶段1-serving工程-kernel入门-第1-3周" tabindex="-1">阶段1：Serving工程 + Kernel入门（第1-3周） <a class="header-anchor" href="#阶段1-serving工程-kernel入门-第1-3周" aria-label="Permalink to &quot;阶段1：Serving工程 + Kernel入门（第1-3周）&quot;">​</a></h3><p>Pan老师已了解 continuous batching、PagedAttention、RadixAttention 原理。 重点转向：实际部署调优 + CUDA/Triton 入门。</p><p><strong>核心目标：</strong></p><ul><li>跑通生产级 serving pipeline（vLLM + SGLang）</li><li>入门 Triton 编程，写第一个 kernel</li><li>理解 GPU 内存层次和 roofline model</li></ul><p><strong>必读材料：</strong></p><ul><li>[ ] <a href="https://arxiv.org/abs/2009.06732" target="_blank" rel="noreferrer">Efficient Transformers Survey (Tay et al., 2022)</a> — 快速过</li><li>[ ] <a href="https://arxiv.org/abs/2205.14135" target="_blank" rel="noreferrer">FlashAttention (Dao et al., 2022)</a> — 必读</li><li>[ ] <a href="https://arxiv.org/abs/2307.08691" target="_blank" rel="noreferrer">FlashAttention-2 (2023)</a></li><li>[ ] <a href="https://arxiv.org/abs/2309.06180" target="_blank" rel="noreferrer">PagedAttention / vLLM (Kwon et al., 2023)</a> — 重点</li><li>[ ] <a href="https://www.usenix.org/conference/osdi22/presentation/yu" target="_blank" rel="noreferrer">Orca: Continuous Batching (Yu et al., 2022)</a></li></ul><p><strong>实操：</strong></p><ul><li>[ ] 部署vLLM，阅读核心源码（scheduler、PagedAttention实现）</li><li>[ ] 部署SGLang，阅读核心源码（RadixAttention、零开销调度器）</li><li>[ ] 对比 vLLM vs SGLang 在不同场景下的性能差异</li><li>[ ] 用benchmark工具对比不同batch策略的throughput和latency</li><li>[ ] 手写一个简单的KV cache管理器</li></ul><h3 id="阶段2-量化与压缩-第4-6周" tabindex="-1">阶段2：量化与压缩（第4-6周） <a class="header-anchor" href="#阶段2-量化与压缩-第4-6周" aria-label="Permalink to &quot;阶段2：量化与压缩（第4-6周）&quot;">​</a></h3><p><strong>核心概念：</strong></p><ul><li>Weight-only quantization vs Weight-Activation quantization</li><li>PTQ（Post-Training Quantization）vs QAT（Quantization-Aware Training）</li><li>Calibration策略</li><li>Mixed-precision推理</li></ul><p><strong>必读论文：</strong></p><ul><li>[ ] <a href="https://arxiv.org/abs/2210.17323" target="_blank" rel="noreferrer">GPTQ (Frantar et al., 2023)</a> — weight-only PTQ经典</li><li>[ ] <a href="https://arxiv.org/abs/2306.00978" target="_blank" rel="noreferrer">AWQ (Lin et al., 2024)</a> — activation-aware量化</li><li>[ ] <a href="https://arxiv.org/abs/2211.10438" target="_blank" rel="noreferrer">SmoothQuant (Xiao et al., 2023)</a> — W8A8</li><li>[ ] <a href="https://arxiv.org/abs/2402.04396" target="_blank" rel="noreferrer">QuIP# (Tseng et al., 2024)</a> — 2-bit量化</li><li>[ ] <a href="https://arxiv.org/abs/2209.05433" target="_blank" rel="noreferrer">FP8 Training &amp; Inference</a></li></ul><p><strong>实操：</strong></p><ul><li>[ ] 用AutoGPTQ/AutoAWQ量化一个模型，对比精度和速度</li><li>[ ] 阅读GPTQ核心代码，理解Hessian-based量化</li><li>[ ] 实现一个简单的per-channel vs per-group量化对比实验</li></ul><h3 id="阶段3-高级优化技术-第7-10周" tabindex="-1">阶段3：高级优化技术（第7-10周） <a class="header-anchor" href="#阶段3-高级优化技术-第7-10周" aria-label="Permalink to &quot;阶段3：高级优化技术（第7-10周）&quot;">​</a></h3><p><strong>核心概念：</strong></p><ul><li>Speculative Decoding</li><li>KV Cache压缩（MLA、GQA、MQA、StreamingLLM）</li><li>Prefill-Decode分离架构（PD disaggregation）</li><li>Structured pruning / Distillation</li></ul><p><strong>必读论文：</strong></p><ul><li>[ ] <a href="https://arxiv.org/abs/2211.17192" target="_blank" rel="noreferrer">Speculative Decoding (Leviathan et al., 2023)</a></li><li>[ ] <a href="https://arxiv.org/abs/2401.10774" target="_blank" rel="noreferrer">Medusa (Cai et al., 2024)</a> — parallel decoding heads</li><li>[ ] <a href="https://arxiv.org/abs/2405.04434" target="_blank" rel="noreferrer">MLA - DeepSeek-V2 (2024)</a> — Multi-head Latent Attention</li><li>[ ] <a href="https://arxiv.org/abs/2309.17453" target="_blank" rel="noreferrer">StreamingLLM (Xiao et al., 2024)</a> — 无限长度推理</li><li>[ ] <a href="https://arxiv.org/abs/2401.09670" target="_blank" rel="noreferrer">DistServe / Splitwise</a> — PD分离</li><li>[ ] <a href="https://arxiv.org/abs/2312.07104" target="_blank" rel="noreferrer">SGLang (Zheng et al., 2024)</a> — RadixAttention</li></ul><p><strong>实操：</strong></p><ul><li>[ ] 实现speculative decoding（draft model + target model）</li><li>[ ] 阅读SGLang源码，理解RadixAttention和prefix caching</li><li>[ ] 对比GQA/MQA/MLA在不同场景下的性能</li></ul><p><strong>项目：</strong></p><ul><li>[ ] 给vLLM或SGLang贡献一个PR（哪怕是小优化）</li><li>[ ] 写一篇推理优化的系统性总结</li></ul><hr><h2 id="学习节奏建议" tabindex="-1">学习节奏建议 <a class="header-anchor" href="#学习节奏建议" aria-label="Permalink to &quot;学习节奏建议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>Agentic RL</th><th>推理优化</th></tr></thead><tbody><tr><td>周一三五</td><td>读论文 + 笔记</td><td>—</td></tr><tr><td>周二四六</td><td>—</td><td>读论文 + 代码</td></tr><tr><td>周日</td><td>实操项目</td><td>实操项目</td></tr></tbody></table><p>灵活调整，核心是保持节奏，不要断。</p><h2 id="学习资源" tabindex="-1">学习资源 <a class="header-anchor" href="#学习资源" aria-label="Permalink to &quot;学习资源&quot;">​</a></h2><h3 id="代码库" tabindex="-1">代码库 <a class="header-anchor" href="#代码库" aria-label="Permalink to &quot;代码库&quot;">​</a></h3><ul><li><a href="https://github.com/huggingface/trl" target="_blank" rel="noreferrer">TRL</a> — RLHF/GRPO训练</li><li><a href="https://github.com/OpenRLHF/OpenRLHF" target="_blank" rel="noreferrer">OpenRLHF</a> — 分布式RLHF</li><li><a href="https://github.com/vllm-project/vllm" target="_blank" rel="noreferrer">vLLM</a> — 推理引擎</li><li><a href="https://github.com/sgl-project/sglang" target="_blank" rel="noreferrer">SGLang</a> — 推理框架</li><li><a href="https://github.com/NVIDIA/TensorRT-LLM" target="_blank" rel="noreferrer">TensorRT-LLM</a> — NVIDIA推理优化</li></ul><h3 id="博客-课程" tabindex="-1">博客/课程 <a class="header-anchor" href="#博客-课程" aria-label="Permalink to &quot;博客/课程&quot;">​</a></h3><ul><li>Hugging Face RLHF blog series</li><li>Lilian Weng&#39;s blog（RL + LLM相关）</li><li>知乎/公众号上的中文解读（辅助理解）</li></ul><hr><blockquote><p>这个路线图会随学习进展持续更新。 每完成一项打个 [x]，Pander会帮你跟踪进度 🐼</p></blockquote>',66)])])}const c=r(i,[["render",n]]);export{d as __pageData,c as default};
